    ForKiDamage = true; --tu ki se pega a broly
    AntiLeech = false; --si alguien entra a tu broly te regresa a queue/tierra
   -- | Transformations
    Transformations = false; --para razas que cargan ki
    ChargeTime = 3; --tiempo de carga
    FormType = "h"; --"g" or "h"
