	UsePunch = false; --usa golpes normales cuando tengas poco ki (aveces da kick)
	AutoBlock = true;
   -- |
	FastGod = false;  --baja el poder para irte mas rapido a god
	MinPower = 10; --(del 5 al 100) mientras mas bajo mas vida te quitan con FastGod, sube o baja cada 5
------------------------------------------------------

   -- Others
   	ExtraTime1 = 0; --para tierra o queue
	ExtraTime2 = 0; --para broly
   -- |
    ViewStats = true; --muestra tus stats
    EnableFakeUser = false;
    FakeUser = "kamu"; --name que quieras mostrar en stats
	UseImageStats = false,
	BannerStats = "1"; --imagen que muestra las stats (from 1 to 8)
	ColorStats = {0, 0, 0}, --deshabilita UseImageStats
   -- |
    UseAnimation = false; --usa emotes
    AssetAnimId = ""; --debes poner el asset id del emote que quieras
	FPSBoost = false; --poop graphics
   -- |
    DuoMode = false; --activalo en las dos cuentas para detectar al carry
    MainAcc = "linda125xd"; --la cuenta a la que se hara tp
	AltAcc = "dbzroox"; --la que usara el tp y dara reds (carry)
	SpamJarsOnly = false; --no ataca y solo spamea jars
------------------------------------------------------

    AutoStats = {
        Enable = false,
        Add = "Phys-Damage"; --[ "Health-Max", "Ki-Resist", "Phys-Resist", "Ki-Damage", "Phys-Damage", "Ki-Max", "Speed" ]
    };
}
